// src/UploadBills.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function UploadBills({ employee }) {
  const navigate = useNavigate();
  const [file, setFile] = useState(null);
  const [billList, setBillList] = useState([]);

  useEffect(() => {
    if (employee?.empld) loadBills();
  }, [employee]);

  const loadBills = async () => {
    const res = await fetch(`${apiBase}/bills?empld=${employee.empld}`);
    const data = await res.json();
    setBillList(Array.isArray(data) ? data : []);
  };

  const handleUpload = async () => {
    if (!file) return alert("Select a bill file first.");

    const fd = new FormData();
    fd.append("bill", file);
    fd.append("empld", employee.empld);

    const res = await fetch(`${apiBase}/upload-bill`, {
      method: "POST",
      body: fd
    });

    const data = await res.json();
    if (data.success) {
      alert("Bill uploaded successfully!");
      loadBills();
      setFile(null);
    } else {
      alert("Upload failed");
    }
  };

  const deleteBill = async (id) => {
    if (!window.confirm("Delete this bill?")) return;

    const res = await fetch(`${apiBase}/bills/${id}`, { method: "DELETE" });
    const data = await res.json();

    if (data.success) {
      alert("Bill deleted");
      loadBills();
    } else {
      alert("Delete failed");
    }
  };

  return (
    <div style={outer}>
      <div style={card}>

        {/* Header */}
        <div style={headerRow}>
          <button onClick={() => navigate("/tools")} style={backBtn}>⬅ Back</button>
          <h2 style={title}>Upload Bills</h2>
        </div>

        <p style={empInfo}>Employee: {employee.name} • {employee.empld}</p>

        {/* Upload Section */}
        <div style={uploadBox}>
          <input type="file" onChange={(e) => setFile(e.target.files[0])} />
          <button style={uploadBtn} onClick={handleUpload}>
            Upload Bill
          </button>
        </div>

        {/* Existing Bill List */}
        <h3 style={{ color: green, marginTop: 20 }}>Uploaded Bills</h3>

        {billList.length === 0 ? (
          <p>No bills uploaded yet.</p>
        ) : (
          <table style={table}>
            <thead>
              <tr>
                <th>Date</th>
                <th>File Name</th>
                <th>Preview</th>
                <th>Delete</th>
              </tr>
            </thead>
            <tbody>
              {billList.map((b) => (
                <tr key={b.id}>
                  <td>{b.created_at?.split?.("T")?.[0]}</td>
                  <td>{b.fileName}</td>
                  <td>
                    <a href={`${apiBase}${b.filePath}`} target="_blank">Open</a>
                  </td>
                  <td>
                    <button onClick={() => deleteBill(b.id)} style={deleteBtn}>
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

      </div>
    </div>
  );
}

// -------- Styles --------
const outer = { minHeight: "100vh", background: lightGreen, padding: 20 };
const card = {
  maxWidth: 900,
  margin: "0 auto",
  padding: 20,
  background: "#fff",
  borderRadius: 16,
  boxShadow: "0 6px 20px rgba(0,0,0,0.1)"
};
const headerRow = { display: "flex", alignItems: "center", gap: 10 };
const backBtn = { background: "none", border: "none", color: green, fontSize: 16, cursor: "pointer" };
const title = { color: green };
const empInfo = { fontSize: 13, color: "#555" };

const uploadBox = { display: "flex", gap: 10, marginTop: 10 };
const uploadBtn = {
  background: green,
  color: "#fff",
  padding: "6px 14px",
  borderRadius: 10,
  border: "none",
  cursor: "pointer"
};
const table = { width: "100%", borderCollapse: "collapse", marginTop: 10 };
const deleteBtn = {
  background: "#c62828",
  color: "#fff",
  padding: "4px 8px",
  borderRadius: 6,
  border: "none",
  cursor: "pointer"
};
